            // Wait for quiescence
            for (int i = 0; i < 100; i++) {
                if (daemon.isBalanced()) {
                    System.out.println("stress-ok cycles=" + cycles);
                    return;
                }
                System.gc();
                Thread.sleep(100);
            }

            throw new IllegalStateException("System did not balance after 10 seconds");
        }
    }
}
